const triggerGroup = typeof msg.triggerGroup === 'string' && msg.triggerGroup.trim() ? msg.triggerGroup.trim() : 'iobroker_in_nodes';
const registered = flow.get(triggerGroup) || {};
const targetId = typeof msg.targetId === 'string' ? msg.targetId.trim() : '';
const targetName = typeof msg.targetName === 'string' ? msg.targetName.trim() : '';
const action = String(msg.action || 'cached').trim().toLowerCase();

const allNodes = Object.entries(registered).map(([id, node]) => ({ id, node }));

function supports(node, selectedAction) {
    if (selectedAction === 'cached') return typeof node.triggerCached === 'function';
    if (selectedAction === 'topic') return node.supportsDynamicTopic && typeof node.triggerWithTopic === 'function';
    if (selectedAction === 'array') return node.supportsDynamicArray && typeof node.triggerWithTopicArray === 'function';
    return false;
}

function pickCandidate(selectedAction) {
    if (targetId && registered[targetId] && supports(registered[targetId], selectedAction)) {
        return { id: targetId, node: registered[targetId] };
    }

    if (targetName) {
        const byName = allNodes.find((entry) => entry.node && entry.node.name === targetName && supports(entry.node, selectedAction));
        if (byName) return byName;
    }

    return allNodes.find((entry) => entry.node && supports(entry.node, selectedAction));
}

function sendSuccess(candidate, extra) {
    msg.dynamicTrigger = Object.assign({
        action,
        triggerGroup,
        targetId: candidate.id,
        targetName: candidate.node.name || '',
        mode: candidate.node.mode || ''
    }, extra || {});

    node.status({ fill: 'green', shape: 'dot', text: `${action} ok` });
    node.send([msg, null]);
    node.done();
}

function sendError(reason) {
    const errMsg = RED.util.cloneMessage(msg);
    errMsg.error = { message: reason, action, triggerGroup, targetId, targetName };
    node.status({ fill: 'red', shape: 'ring', text: reason });
    node.send([null, errMsg]);
    node.done();
}

if (!['cached', 'topic', 'array'].includes(action)) {
    sendError('msg.action must be cached, topic or array');
    return;
}

const candidate = pickCandidate(action);
if (!candidate || !candidate.node) {
    sendError('No compatible iob-in node found for requested action');
    return;
}

if (action === 'cached') {
    try {
        candidate.node.triggerCached();
        sendSuccess(candidate);
    } catch (error) {
        sendError(`Cached trigger failed: ${error.message}`);
    }
    return;
}

if (action === 'topic') {
    const topic = typeof msg.topic === 'string' ? msg.topic.trim() : '';
    if (!topic) {
        sendError('msg.topic must be a non-empty string for action=topic');
        return;
    }

    candidate.node.triggerWithTopic(topic)
        .then(() => sendSuccess(candidate, { topic }))
        .catch((error) => sendError(`Topic switch failed: ${error.message}`));
    return;
}

const rawTopics = Array.isArray(msg.payload) ? msg.payload : (Array.isArray(msg.topics) ? msg.topics : []);
const topics = rawTopics.filter((item) => typeof item === 'string').map((item) => item.trim()).filter(Boolean);
if (topics.length === 0) {
    sendError('Provide topics as non-empty string array in msg.payload or msg.topics for action=array');
    return;
}

const outputMode = msg.outputMode === 'individual' || msg.outputMode === 'grouped' ? msg.outputMode : undefined;
candidate.node.triggerWithTopicArray(topics, outputMode)
    .then(() => sendSuccess(candidate, { topicsCount: topics.length, outputMode: outputMode || 'unchanged' }))
    .catch((error) => sendError(`Array switch failed: ${error.message}`));
